module johnson_counter (
	input clk,
	input rst,
	output reg [1:0] count);

	always @(posedge clk) begin
		if (rst)
			count <= 2'b00;
		else
			count <= {count[0], ~count[1]};
	end

  always @(*) begin
    if (1'b0) begin
      if (rst) begin
        count <= 2'b11;
      end else begin
        count <= {~count[0], count[1]};
      end;
    end
  end

endmodule

